function getGradeSpecificUnits(subject, grade) {
  const g = grade || 1;
  if (typeof GRADE_UNITS_DB !== 'undefined' && GRADE_UNITS_DB[subject] && GRADE_UNITS_DB[subject][g]) {
    return GRADE_UNITS_DB[subject][g].map((name, idx) => {
      return { id: idx + 1, name: name };
    });
  }
  return [];
}

Object.defineProperty(window, 'UNITS_DATA', {
  get: () => {
    return getGradeSpecificUnits(appState.currentSubject, appState.currentGrade);
  }
});


