function getLessonTitleAndDesc(subject, grade, lessonId) {
  if (grade === 1) {
    if (subject === 'math') return LESSON_TITLES[lessonId] || [`Lesson ${lessonId}`, "Learn Grade 1 Math standard."];
    if (subject === 'ela') return ELA_LESSON_TITLES[lessonId] || [`Lesson ${lessonId}`, "Learn Grade 1 ELA standard."];
    if (subject === 'history') return HISTORY_LESSON_TITLES[lessonId] || [`Lesson ${lessonId}`, "Learn Grade 1 History."];
    if (subject === 'geography') return GEOGRAPHY_LESSON_TITLES[lessonId] || [`Lesson ${lessonId}`, "Learn Grade 1 Geography."];
    if (subject === 'science') return SCIENCE_LESSON_TITLES[lessonId] || [`Lesson ${lessonId}`, "Learn Grade 1 Science."];
    if (subject === 'art') return ART_LESSON_TITLES[lessonId] || [`Lesson ${lessonId}`, "Learn Grade 1 Art."];
  }

  // Science, History, Geography, Art for Grade >= 2:
  // Dynamically load from our GRADE_2_5_QUESTIONS database to make sure they match 100%!
  const isSpecial = (subject === 'science' || subject === 'history' || subject === 'geography' || subject === 'art');
  if (grade >= 2 && isSpecial) {
    if (typeof GRADE_2_5_QUESTIONS !== 'undefined' && 
        GRADE_2_5_QUESTIONS[subject] && 
        GRADE_2_5_QUESTIONS[subject][grade] && 
        GRADE_2_5_QUESTIONS[subject][grade][lessonId]) {
      const qList = GRADE_2_5_QUESTIONS[subject][grade][lessonId];
      if (qList && qList[0]) {
        const theme = qList[0].theme || `Lesson ${lessonId}`;
        const fact = qList[0].fact_stem || "Learn this topic.";
        const cleanFact = fact.replace(/\.*$/, "").trim();
        return [theme, `Learn that ${theme.toLowerCase()} ${cleanFact}.`];
      }
    }
  }

  // Math and ELA for Grade >= 2:
  // Load from our hardcoded GRADE_2_5_LESSON_DETAILS!
  if (typeof GRADE_2_5_LESSON_DETAILS !== 'undefined' &&
      GRADE_2_5_LESSON_DETAILS[subject] &&
      GRADE_2_5_LESSON_DETAILS[subject][grade] &&
      GRADE_2_5_LESSON_DETAILS[subject][grade][lessonId]) {
    return GRADE_2_5_LESSON_DETAILS[subject][grade][lessonId];
  }

  return [`Lesson ${lessonId}`, `Learn Grade ${grade} ${subject} standard.`];
}

